import type { ReactElement, ReactNode } from 'react';
import { isElement } from 'react-is';

import { useBehavioralTrackingProps } from '../../../../core/hooks/useBehavioralTrackingProps.js';
import type { BehaviorTrackingProps } from '../../../../core/types/behavior-tracking-props.js';
import { canReceiveDefaultTextFormat } from '../../../../core/utils/can-receive-default-text-format.js';
import { Text } from '../../../../typography/text/Text.js';
import { useTimeframeSelectorContext } from '../../hooks/useTimeframeSelectorContext.js';

/**
 * @public
 */
export type TimeframeSelectorDisplayValueProps = BehaviorTrackingProps & {
  children?:
    | ReactNode
    | ((customTriggerProps: { displayValue: ReactNode }) => ReactElement);
};

/**
 * Typeguard function that will check if a Node is a TimeframeSelector.DisplayValue
 * @internal
 */
export function isTimeframeSelectorDisplayValueElement(
  child: ReactNode,
): child is ReactElement<TimeframeSelectorDisplayValueProps> {
  return isElement(child) && child.type === DisplayValue;
}

/**
 * `TimeframeSelector.DisplayValue` defines a custom display value within the Trigger. A TimeframeSelector.DisplayValue component
 * is only valid within a TimeframeSelector.Trigger.
 * @public
 */
export const DisplayValue = (props: TimeframeSelectorDisplayValueProps) => {
  const { children, ...remainingProps } = props;
  const [behavioralTrackingProps] = useBehavioralTrackingProps(remainingProps);

  const { displayValue } = useTimeframeSelectorContext();

  if (!children) {
    return null;
  }

  if (typeof children === 'function') {
    return children({ displayValue });
  }

  if (canReceiveDefaultTextFormat(children)) {
    return (
      <Text as="p" {...behavioralTrackingProps}>
        {children}
      </Text>
    );
  }

  if (isElement(children)) {
    return children;
  }

  return null;
};

DisplayValue.displayName = 'TimeframeSelector.DisplayValue';
